/// GET v2/reports
/// Retrieve your YouTube Analytics reports.
///
/// Returns `ClientRequestBuilder` for customization.
/// Use `youtube_analytics_reports_query_execute()` to send, or `youtube_analytics_reports_query` for simplest API.

pub fn youtube_analytics_reports_query_builder(
    client: &SimpleHttpClient,
    currency: Option<&str>,
    dimensions: Option<&str>,
    endDate: Option<&str>,
    filters: Option<&str>,
    ids: Option<&str>,
    includeHistoricalChannelData: Option<bool>,
    maxResults: Option<i32>,
    metrics: Option<&str>,
    sort: Option<&str>,
    startDate: Option<&str>,
    startIndex: Option<i32>,
) -> Result<ClientRequestBuilder<SystemDnsResolver>, ApiError> {
    // Build URL
    let url = format!("https://api.example.comv2/reports",);

    // Build request
    client
        .get(&url)
        .map_err(|e| ApiError::RequestBuildFailed(e.to_string()))
        .query(
            "currency",
            currency
                .as_ref()
                .map(|s| s.to_string())
                .unwrap_or_default()
                .as_str(),
        )
        .query(
            "dimensions",
            dimensions
                .as_ref()
                .map(|s| s.to_string())
                .unwrap_or_default()
                .as_str(),
        )
        .query(
            "endDate",
            endDate
                .as_ref()
                .map(|s| s.to_string())
                .unwrap_or_default()
                .as_str(),
        )
        .query(
            "filters",
            filters
                .as_ref()
                .map(|s| s.to_string())
                .unwrap_or_default()
                .as_str(),
        )
        .query(
            "ids",
            ids.as_ref()
                .map(|s| s.to_string())
                .unwrap_or_default()
                .as_str(),
        )
        .query(
            "includeHistoricalChannelData",
            includeHistoricalChannelData
                .as_ref()
                .map(|s| s.to_string())
                .unwrap_or_default()
                .as_str(),
        )
        .query(
            "maxResults",
            maxResults
                .as_ref()
                .map(|s| s.to_string())
                .unwrap_or_default()
                .as_str(),
        )
        .query(
            "metrics",
            metrics
                .as_ref()
                .map(|s| s.to_string())
                .unwrap_or_default()
                .as_str(),
        )
        .query(
            "sort",
            sort.as_ref()
                .map(|s| s.to_string())
                .unwrap_or_default()
                .as_str(),
        )
        .query(
            "startDate",
            startDate
                .as_ref()
                .map(|s| s.to_string())
                .unwrap_or_default()
                .as_str(),
        )
        .query(
            "startIndex",
            startIndex
                .as_ref()
                .map(|s| s.to_string())
                .unwrap_or_default()
                .as_str(),
        )
}

/// GET v2/reports
/// Retrieve your YouTube Analytics reports.
///
/// Takes a `ClientRequestBuilder`, builds and executes the request.
/// For customization, use `youtube_analytics_reports_query_builder()` then pass to this function.
///
/// # Arguments
///
/// * `builder` - ClientRequestBuilder from youtube_analytics_reports_query_builder()
///
/// # Errors
///
/// Returns an error if the request cannot be built.

pub fn youtube_analytics_reports_query_execute(
    builder: ClientRequestBuilder<SystemDnsResolver>,
) -> Result<
    impl StreamIterator<D = Result<ApiResponse<QueryResponse>, ApiError>, P = ApiPending>
        + Send
        + 'static,
    ApiError,
> {
    // Get SendRequestTask from builder
    let task = builder
        .build_send_request()
        .map_err(|e| ApiError::RequestBuildFailed(e.to_string()))?
        .map_ready(|intro| match intro {
            RequestIntro::Success { stream, status } => {
                let headers = status.headers().clone();

                if !status.is_success() {
                    return Err(ApiError::HttpStatus {
                        code: status.as_u16(),
                        headers,
                    });
                }

                let body = body_reader::collect_string(stream);
                let parsed: QueryResponse = serde_json::from_str(&body)
                    .map_err(|e| ApiError::ParseFailed(e.to_string()))?;

                Ok(ApiResponse {
                    status: status.as_u16(),
                    headers,
                    body: parsed,
                })
            }
            RequestIntro::Failed(e) => Err(ApiError::RequestSendFailed(e.to_string())),
        })
        .map_pending(|_| ApiPending::Sending);

    // Convert TaskIterator to StreamIterator
    execute(task, None).map_err(|e| ApiError::RequestBuildFailed(e.to_string()))
}

